using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Paging;using verii_metivon_api.Core.UnitOfWork;using verii_metivon_api.Modules.Counting.Application.Parameters;using verii_metivon_api.Modules.Counting.Domain.Entities;using verii_metivon_api.Modules.Inventory.Application.Services;using verii_metivon_api.Modules.Inventory.Domain.Entities;using verii_metivon_api.Modules.Inventory.Domain.Enums;using verii_metivon_api.Modules.Products.Domain.Entities;using verii_metivon_api.Modules.Warehouses.Domain.Entities;
namespace verii_metivon_api.Modules.Counting.Application.Services;
public sealed class InventoryCountQuery:PagedQuery{public long?WarehouseId{get;init;}public InventoryCountStatus?Status{get;init;}}public sealed record InventoryCountRow(long Id,string CountNumber,string WarehouseCode,DateOnly CountDate,bool IsBlindCount,int LineCount,decimal TotalDifference,string Status);public sealed record CreateInventoryCountRequest(string?CountNumber,long WarehouseId,long?StorageLocationId,DateOnly CountDate,bool IsBlindCount,string?Notes);public sealed record CountEntry(long LineId,decimal CountedQuantity,string?ReasonCode,string?Notes);public interface IInventoryCountService{Task<ApiResponse<PagedResult<InventoryCountRow>>>GetPagedAsync(InventoryCountQuery q,CancellationToken ct);Task<ApiResponse<object>>CreateAsync(CreateInventoryCountRequest r,CancellationToken ct);Task<ApiResponse<object>>EnterAsync(long id,IReadOnlyList<CountEntry> lines,CancellationToken ct);Task<ApiResponse<object>>ApproveAsync(long id,CancellationToken ct);Task<ApiResponse<object>>PostAsync(long id,CancellationToken ct);}
public sealed class InventoryCountService(IUnitOfWork u,IInventoryService inventory,IInventoryCountParameterService parameters):IInventoryCountService
{
public async Task<ApiResponse<PagedResult<InventoryCountRow>>>GetPagedAsync(InventoryCountQuery q,CancellationToken ct){var x=u.Repository<InventoryCount>().Query().Include(v=>v.Warehouse).Include(v=>v.Lines).AsQueryable();if(q.WarehouseId.HasValue)x=x.Where(v=>v.WarehouseId==q.WarehouseId);if(q.Status.HasValue)x=x.Where(v=>v.Status==q.Status);if(!string.IsNullOrWhiteSpace(q.Search)){var s=q.Search.Trim();x=x.Where(v=>v.CountNumber.Contains(s));}x=x.ApplyPagedFilters(q);var total=await x.CountAsync(ct);var rows=await x.OrderByDescending(v=>v.CountDate).ThenByDescending(v=>v.Id).Skip((q.NormalizedPageNumber-1)*q.NormalizedPageSize).Take(q.NormalizedPageSize).Select(v=>new InventoryCountRow(v.Id,v.CountNumber,v.Warehouse.Code,v.CountDate,v.IsBlindCount,v.Lines.Count,v.Lines.Sum(l=>l.DifferenceQuantity),v.Status.ToString())).ToListAsync(ct);return ApiResponse<PagedResult<InventoryCountRow>>.Ok(new(rows,q.NormalizedPageNumber,q.NormalizedPageSize,total));}
public async Task<ApiResponse<object>>CreateAsync(CreateInventoryCountRequest r,CancellationToken ct){var warehouse=await u.Repository<Warehouse>().Query().Where(x=>x.Id==r.WarehouseId&&x.IsActive).Select(x=>new{x.Id,x.BranchId}).FirstOrDefaultAsync(ct);if(warehouse is null)return ApiResponse<object>.Error("Warehouse is not active or could not be found.",400);var p=await parameters.ResolveSettingsAsync(warehouse.BranchId,r.WarehouseId,ct);if(!p.AllowPastCountDate&&r.CountDate<DateOnly.FromDateTime(DateTime.UtcNow))return ApiResponse<object>.Error("Past count date is disabled by counting parameters.",400);if(p.RequireStorageLocation&&!r.StorageLocationId.HasValue)return ApiResponse<object>.Error("Storage location is required.",400);if(p.PreventOverlappingOpenCounts&&await u.Repository<InventoryCount>().ExistsAsync(x=>x.WarehouseId==r.WarehouseId&&x.StorageLocationId==r.StorageLocationId&&x.Status!=InventoryCountStatus.Posted&&x.Status!=InventoryCountStatus.Cancelled,ct))return ApiResponse<object>.Error("An open inventory count already exists for this scope.",409);var balancesQuery=u.Repository<InventoryBalance>().Query().Where(x=>x.WarehouseId==r.WarehouseId&&(!r.StorageLocationId.HasValue||x.StorageLocationId==r.StorageLocationId));if(!p.IncludeZeroBalances)balancesQuery=balancesQuery.Where(x=>x.PhysicalQuantity!=0);var balances=await balancesQuery.ToListAsync(ct);if(balances.Count>p.MaximumLinesPerCount)return ApiResponse<object>.Error($"Inventory count cannot exceed {p.MaximumLinesPerCount} lines.",400);var productIds=balances.Select(x=>x.ProductId).Distinct().ToArray();var unitMap=await u.Repository<Product>().Query().Where(x=>productIds.Contains(x.Id)).ToDictionaryAsync(x=>x.Id,x=>x.BaseUnitId,ct);string number;try{number=await parameters.ResolveCountNumberAsync(r.CountNumber,warehouse.BranchId,ct);}catch(InvalidOperationException exception){return ApiResponse<object>.Error(exception.Message,400);}if(await u.Repository<InventoryCount>().ExistsAsync(x=>x.CountNumber==number,ct))return ApiResponse<object>.Error("Count number already exists.",409);var e=new InventoryCount{CountNumber=number,WarehouseId=r.WarehouseId,StorageLocationId=r.StorageLocationId,CountDate=r.CountDate,IsBlindCount=p.DefaultBlindCount||r.IsBlindCount,Status=p.FreezeOnCreate?InventoryCountStatus.Frozen:InventoryCountStatus.Draft,FrozenAt=p.FreezeOnCreate?DateTime.UtcNow:null,Notes=r.Notes};var n=0;foreach(var b in balances)e.Lines.Add(new InventoryCountLine{LineNumber=++n,ProductId=b.ProductId,StorageLocationId=b.StorageLocationId,InventoryStatusId=b.InventoryStatusId,InventoryLotId=b.InventoryLotId,InventorySerialId=b.InventorySerialId,UnitId=unitMap[b.ProductId],SystemQuantity=b.PhysicalQuantity,UnitCost=b.PhysicalQuantity==0?0:b.InventoryValue/b.PhysicalQuantity});await u.ExecuteInTransactionAsync(async t=>{await u.Repository<InventoryCount>().AddAsync(e,t);await u.SaveChangesAsync(t);},ct);return ApiResponse<object>.Ok(new{e.Id,e.CountNumber,e.Status});}
public async Task<ApiResponse<object>>EnterAsync(long id,IReadOnlyList<CountEntry> entries,CancellationToken ct){var e=await u.Repository<InventoryCount>().Query(true).Include(x=>x.Lines).Include(x=>x.Warehouse).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return ApiResponse<object>.Error("Count not found.",404);if(e.Status is InventoryCountStatus.Posted or InventoryCountStatus.Cancelled)return ApiResponse<object>.Error("Count is closed.",409);var p=await parameters.ResolveSettingsAsync(e.Warehouse.BranchId,e.WarehouseId,ct);foreach(var source in entries){if(!p.AllowNegativeCountedQuantity&&source.CountedQuantity<0)return ApiResponse<object>.Error("Negative counted quantity is disabled.",400);var line=e.Lines.FirstOrDefault(x=>x.Id==source.LineId);if(line is null)return ApiResponse<object>.Error("Count line does not belong to this document.",400);line.CountedQuantity=source.CountedQuantity;line.DifferenceQuantity=source.CountedQuantity-line.SystemQuantity;if(p.RequireReasonCodeForDifference&&line.DifferenceQuantity!=0&&string.IsNullOrWhiteSpace(source.ReasonCode))return ApiResponse<object>.Error("Reason code is required for count differences.",400);line.ReasonCode=source.ReasonCode?.Trim().ToUpperInvariant();line.Notes=source.Notes;}if(e.Lines.All(x=>x.CountedQuantity.HasValue)){var within=e.Lines.All(x=>Math.Abs(x.DifferenceQuantity)<=p.AutomaticApprovalQuantityTolerance||(x.SystemQuantity!=0&&Math.Abs(x.DifferenceQuantity/x.SystemQuantity*100m)<=p.AutomaticApprovalPercentTolerance));e.Status=p.AutoApproveWithinTolerance&&within?InventoryCountStatus.Approved:InventoryCountStatus.PendingApproval;}else e.Status=InventoryCountStatus.Counting;await u.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{e.Id,e.Status});}
public async Task<ApiResponse<object>>ApproveAsync(long id,CancellationToken ct){var e=await u.Repository<InventoryCount>().GetByIdForUpdateAsync(id,ct);if(e is null)return ApiResponse<object>.Error("Count not found.",404);if(e.Status!=InventoryCountStatus.PendingApproval)return ApiResponse<object>.Error("Only pending counts can be approved.",409);e.Status=InventoryCountStatus.Approved;await u.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{e.Id,e.Status});}
public async Task<ApiResponse<object>>PostAsync(long id,CancellationToken ct){var e=await u.Repository<InventoryCount>().Query(true).Include(x=>x.Lines).Include(x=>x.Warehouse).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return ApiResponse<object>.Error("Count not found.",404);var p=await parameters.ResolveSettingsAsync(e.Warehouse.BranchId,e.WarehouseId,ct);if(e.Lines.Any(x=>!x.CountedQuantity.HasValue))return ApiResponse<object>.Error("All lines must be counted.",409);if(p.RequireApprovalBeforePosting&&e.Status!=InventoryCountStatus.Approved)return ApiResponse<object>.Error("Inventory count approval is required before posting.",409);if(!p.AllowPostingWithoutDifference&&e.Lines.All(x=>x.DifferenceQuantity==0))return ApiResponse<object>.Error("Posting a count without differences is disabled.",409);await u.ExecuteInTransactionAsync(async t=>{Guid?posting=null;foreach(var group in e.Lines.Where(x=>x.DifferenceQuantity!=0).GroupBy(x=>x.DifferenceQuantity>0)){var direction=group.Key?InventoryMovementDirection.Receipt:InventoryMovementDirection.Issue;var movement=group.Key?InventoryMovementType.CountGain:InventoryMovementType.CountLoss;var lines=group.Select(x=>new PostInventoryLine(x.ProductId,x.UnitId,e.WarehouseId,x.StorageLocationId,x.InventoryStatusId,x.InventoryLotId,x.InventorySerialId,Math.Abs(x.DifferenceQuantity),x.UnitCost,x.Id,x.ReasonCode)).ToList();var result=await inventory.PostAsync(new($"COUNT:{e.Id}:{direction}","InventoryCount",e.Id,e.CountNumber,e.CountDate.ToDateTime(TimeOnly.MinValue),movement,direction,p.PostingCurrencyCode,lines),t);if(!result.Success)throw new InvalidOperationException(result.Message);posting=result.Data!.PostingId;}e.InventoryPostingId=posting;e.Status=InventoryCountStatus.Posted;e.PostedAt=DateTime.UtcNow;await u.SaveChangesAsync(t);},ct);return ApiResponse<object>.Ok(new{e.Id,e.InventoryPostingId});}}


